const fs = require('fs');
let lines = [];
try { lines = fs.readFileSync('/config/energy-sources.txt','utf8').split(/\r?\n/); } catch (e) {}
const urls = lines.map(function(l){ return l.trim(); }).filter(function(l){ return l && l.charAt(0) !== '#'; });
if (!urls.length) { return [{ json: { url: '' } }]; }
return urls.map(function(u){ return { json: { url: u } }; });

const items = $input.all();
const arts = items.map(function(i){ return i.json; }).filter(function(a){ return a && (a.title || a.contentSnippet || a.content); });
const companies = [
  ['ADNOC', /adnoc|borouge|ta.?ziz|upper zakum|\bxrg\b/i],
  ['Saudi Aramco', /aramco/i],
  ['QatarEnergy', /qatarenergy|qatar energy/i],
  ['Kuwait Petroleum', /kuwait petroleum|\bkpc\b|kuwait oil/i],
  ['TAQA / Masdar / Mubadala', /\btaqa\b|masdar|mubadala/i],
  ['Shell', /\bshell\b/i],
  ['BP', /\bbp\b/i],
  ['Chevron', /chevron/i],
  ['ExxonMobil', /exxon/i],
  ['TotalEnergies', /totalenergies|total energies/i]
];
function detect(a){ var s=((a.title||'')+' '+(a.contentSnippet||a.content||'')).toString(); for(var i=0;i<companies.length;i++){ if(companies[i][1].test(s)) return companies[i][0]; } return 'Other'; }
function getImg(a){ try { if(a.enclosure && a.enclosure.url) return a.enclosure.url; var mc=a['media:content']||a.mediaContent; if(mc){ if(Array.isArray(mc)) mc=mc[0]; if(mc){ if(mc.url) return mc.url; if(mc['$'] && mc['$'].url) return mc['$'].url; } } var mt=a['media:thumbnail']||a.mediaThumbnail; if(mt){ if(Array.isArray(mt)) mt=mt[0]; if(mt){ if(mt.url) return mt.url; if(mt['$'] && mt['$'].url) return mt['$'].url; } } var c=(a.content||a['content:encoded']||'').toString(); var m=c.match(/<img[^>]+src=["']([^"']+)["']/i); if(m) return m[1]; } catch(e){} return ''; }
function fmt(a){ var t=(a.title||'').toString(); var s=(a.contentSnippet||a.content||'').toString().replace(/\s+/g,' ').slice(0,200); var u=(a.link||a.url||'').toString(); var im=getImg(a); return '- ' + t + ' — ' + s + ' (' + u + ')' + (im?(' IMG='+im):''); }
var buckets={};
arts.forEach(function(a){ var k=detect(a); (buckets[k]=buckets[k]||[]).push(a); });
var order=Object.keys(buckets);
var perCompany=4; var lines=[];
for(var r=0;r<perCompany;r++){ for(var c=0;c<order.length;c++){ var arr=buckets[order[c]]; if(arr[r]){ lines.push('['+order[c]+'] '+fmt(arr[r])); } } }
var text = lines.length ? lines.join('\n') : 'No source articles were retrieved this period.';
var previous='';
try {
  var fs=require('fs'); var dir='/reports/archive/energy-intelligence';
  var today=new Date().toISOString().slice(0,10);
  var files=fs.readdirSync(dir).filter(function(fn){ return /energy-intelligence-\d{4}-\d{2}-\d{2}\.json$/.test(fn) && fn.indexOf(today)===-1; }).sort();
  if(files.length){
    var prev=JSON.parse(fs.readFileSync(dir+'/'+files[files.length-1],'utf8'));
    var ple=[];
    ['noc','ioc'].forEach(function(sec){ (prev[sec]||[]).forEach(function(row){ ple.push('- '+(row.company||'')+': '+((row.development||'').toString().slice(0,160))); }); });
    previous='From '+files[files.length-1].replace('energy-intelligence-','').replace('.json','')+':\n'+ple.join('\n');
  }
} catch(e){ previous=''; }
return [{ json: { articles: text, count: arts.length, date: new Date().toISOString().slice(0,10), previous: previous } }];

const j = $json || {};
let md = '';
if (j.message && j.message.content) { md = j.message.content; }
else if (j.content && j.content[0] && j.content[0].text) { md = j.content[0].text; }
else if (typeof j.markdown === 'string') { md = j.markdown; }
md = md || '';
const top = md.split(/\n/).filter(function(l){ return /adnoc|energy|oil|gas|lng|masdar|taqa/i.test(l); }).slice(0,4).join('; ') || 'UAE and ADNOC energy sector developments';
const style = 'Premium editorial intelligence-report cover. Deep navy (#0A1A2F) background with refined gold (#C9A24B) accents. Abstract professional energy motifs. NO text, NO logos, NO faces.';
return [{ json: { markdown: md || 'No data available for this period.', date: new Date().toISOString().slice(0,10), coverPrompt: style + ' Visual theme inspired by: ' + top } }];

let raw = ($json && $json.markdown) || '';
function tryParse(s){ try { return JSON.parse(s); } catch(e){ return null; } }
function repair(s){ var i0=s.indexOf('{'); if(i0<0) return null; s=s.slice(i0); var stack=[],inStr=false,esc=false,cut=-1,cutStack=null; for(var i=0;i<s.length;i++){ var ch=s[i]; if(esc){esc=false;continue;} if(ch==='\\'){esc=true;continue;} if(ch==='"'){inStr=!inStr;continue;} if(inStr)continue; if(ch==='{'||ch==='['){stack.push(ch);} else if(ch==='}'||ch===']'){stack.pop(); cut=i+1; cutStack=stack.slice();} } if(cut<0) return null; var out=s.slice(0,cut); for(var k=cutStack.length-1;k>=0;k--){ out += cutStack[k]==='{' ? '}' : ']'; } return out; }
var cleaned = raw.replace(/^\uFEFF/,'').trim().replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'').trim();
var data = tryParse(cleaned);
if(!data){ var m = cleaned.match(/\{[\s\S]*\}/); if(m) data = tryParse(m[0]); }
if(!data){ var rep = repair(cleaned); if(rep) data = tryParse(rep); }
try { if(data){ var _lp=$('Fetch Market Prices').first().json.marketPrices; if(_lp && _lp.length){ data.financial=data.financial||{}; data.financial.prices=_lp; } } } catch(e){}
const date = ($json && $json.date) || new Date().toISOString().slice(0,10);
const fs = require('fs');
function fileUri(base){ var t=[['/config/branding/'+base+'.png','image/png'],['/config/branding/'+base+'.jpg','image/jpeg'],['/config/branding/'+base+'.jpeg','image/jpeg']]; for(var i=0;i<t.length;i++){ try { return 'data:'+t[i][1]+';base64,'+fs.readFileSync(t[i][0]).toString('base64'); } catch(e){} } return ''; }
const cover=fileUri('cover'), banner=fileUri('banner'), avatar=fileUri('jarvis-avatar');
let hero=''; try { var hb=$('Generate Cover (Image Provider)').first().json.data[0].b64_json; if(hb) hero='data:image/png;base64,'+hb; } catch(e){ hero=''; }
if(!hero){ hero = fileUri('hero') || banner || cover; }
function ord(n){ var s=['th','st','nd','rd'], v=n%100; return n+(s[(v-20)%10]||s[v]||s[0]); }
function prettyDate(d){ try { var p=(d||'').split('-'); var dt=new Date(Number(p[0]),Number(p[1])-1,Number(p[2])); var M=['January','February','March','April','May','June','July','August','September','October','November','December']; return M[dt.getMonth()]+' '+ord(dt.getDate())+' '+dt.getFullYear(); } catch(e){ return d; } }
const dateStr=prettyDate(date), weekOf=(data&&data.weekOf)?data.weekOf:dateStr;
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function riskColor(r){ r=(r||'').toString().toLowerCase(); if(r.indexOf('high')===0)return '#B02525'; if(r.indexOf('med')===0)return '#B8860B'; if(r.indexOf('low')===0)return '#1E8E5A'; return '#5A6472'; }

var BCSS='*{box-sizing:border-box} body{margin:0;font-family:-apple-system,"Segoe UI",Arial,sans-serif;color:#11151c;font-size:14px;line-height:1.55} '
 + '.wrap{padding:22px 40px 10px} '
 + '.lead{font-size:16px;line-height:1.75;margin:0 0 4px} .lead .dc{float:left;font-family:Georgia,serif;font-size:56px;line-height:44px;padding:6px 12px 0 0;color:#2E9BE6;font-weight:700} '
