function secH(kick,title,first){ return '<div class="sec'+(first?' first':'')+'"><h2 class="h"><span class="kick">'+esc(kick)+'</span>'+esc(title)+'</h2>'; }
function lead(t){ t=(t||'').toString().trim(); if(!t)return''; var parts=t.split(/\n+/).map(function(x){return x.trim();}).filter(function(x){return x;}); if(!parts.length)return''; var h='<p class="lead"><span class="dc">'+esc(parts[0].charAt(0))+'</span>'+esc(parts[0].slice(1))+'</p>'; for(var i=1;i<parts.length;i++){ h+='<p class="lead" style="margin-top:10px">'+esc(parts[i])+'</p>'; } return h; }
