function co(r){ function row(l,v,c){ if(v==null||v==='')v='Not specified'; var x=c?('<span style="color:'+c+';font-weight:700">'+esc(v)+'</span>'):esc(v); return '<div class="row"><span class="lab">'+l+'</span>'+x+'</div>'; } return '<div class="co"><div class="hd">'+esc(r.company)+'</div><div class="bd">'+row('Key Development',r.development)+row('Strategic Theme',r.theme)+row('What It Signals',r.signals)+row('Market Impact / Risk',r.risk,riskColor(r.risk))+row('Watch Point',r.watch)+'</div></div>'; }
function movers(rows){ if(!rows||!rows.length)return '<p style="color:#5A6472">No notable leadership changes this period.</p>'; var h='<tr>'+['Company','Individual','Previous role','New role','Effective','Why it matters'].map(function(x){return '<th>'+x+'</th>';}).join('')+'</tr>'; var b=rows.map(function(r){return '<tr><td><b>'+esc(r.company)+'</b></td><td>'+esc(r.individual)+'</td><td>'+esc(r.previous)+'</td><td>'+esc(r.current)+'</td><td>'+esc(r.date)+'</td><td>'+esc(r.why)+'</td></tr>';}).join(''); return '<table class="mv">'+h+b+'</table>'; }

function secIntro(t){ t=(t==null?'':String(t)).trim(); if(!t)return''; return '<p class="secintro">'+esc(t)+'</p>'; }
function chCol(ch){ ch=(ch||'').toString(); if(/(^|\s)-|down|fell|lower|drop|decline/i.test(ch))return '#B02525'; if(/\+|up|rose|higher|gain|climb|surge/i.test(ch))return '#1E8E5A'; return '#5A6472'; }
function chArr(ch){ ch=(ch||'').toString(); if(/(^|\s)-|down|fell|lower|drop|decline/i.test(ch))return '\u25BC '; if(/\+|up|rose|higher|gain|climb|surge/i.test(ch))return '\u25B2 '; return ''; }
function financial(fin){ if(!fin)return''; var prices=fin.prices||[]; var cards=prices.map(function(p){ var col=chCol(p.change); return '<div class="metric"><div class="nm">'+esc(p.name)+'</div><div class="vl">'+esc(p.value||'\u2014')+'</div><div class="ch" style="color:'+col+'">'+chArr(p.change)+esc(p.change||'Not specified')+'</div></div>'; }).join(''); var h=''; if(cards)h+='<div class="metrics">'+cards+'</div>'; if(fin.outlook)h+='<div class="callout"><b>Price outlook &amp; predictions:</b> '+esc(fin.outlook)+'</div>'; if(fin.adnocTrading)h+='<div class="finblock"><h4>ADNOC Trading &amp; ADNOC Global Trading</h4><p>'+esc(fin.adnocTrading)+'</p></div>'; if(fin.adnocFinancials)h+='<div class="finblock"><h4>ADNOC \u2014 Key Financial Analysis</h4><p>'+esc(fin.adnocFinancials)+'</p></div>'; return h; }
function bodyInner(){
  if(!data){ return '<div class="wrap"><div class="callout" style="background:#FDECEC;border-color:#B02525">The analyst did not return structured data this run. Raw output below.</div><pre style="white-space:pre-wrap;font-size:12px">'+esc(raw)+'</pre></div>'; }
  var bonus=data.bonus||{}, feats=data.featured||[], noc=data.noc||[], ioc=data.ioc||[];
  var endbanner='';
  var heroBand = hero ? ('<div style="height:215px;background:#0A1A2F url('+hero+') center/cover no-repeat;border-radius:8px;position:relative;overflow:hidden;margin:0 0 20px"><div style="position:absolute;left:0;right:0;bottom:0;padding:18px 20px 14px;background:linear-gradient(0deg,rgba(10,26,47,.9),rgba(10,26,47,0))"><div style="font-family:Georgia,serif;font-size:24px;font-weight:700;color:#fff;line-height:1.15">Weekly Energy Brief</div><div style="font-size:13px;color:#CFE3F5;margin-top:3px;letter-spacing:.5px">'+esc(dateStr)+'</div></div></div>') : '';
  var signoff=avatar?('<div style="text-align:center;padding:22px 0 6px;border-top:3px solid #2E9BE6;margin-top:22px"><img src="'+avatar+'" style="width:96px;height:96px;border-radius:50%;border:2px solid #2E9BE6"/><div style="font-family:Georgia,serif;color:#0A1A2F;margin-top:8px;font-size:14px">Jarvis — AI News Reporter</div></div>'):'';
  var h='<div class="wrap">';
