const inp = ($input.first() && $input.first().json) || {};
const symbols = [
  ['Brent Crude','BZ=F','$','/bbl'],
  ['WTI','CL=F','$','/bbl'],
  ['Natural Gas (Henry Hub)','NG=F','$','/MMBtu'],
  ['Dutch TTF Gas','TTF=F','\u20ac','/MWh'],
  ['RBOB Gasoline','RB=F','$','/gal']
];
const prices=[]; const dlines=[];
for (let i=0;i<symbols.length;i++){
  const name=symbols[i][0], sym=symbols[i][1], pre=symbols[i][2], suf=symbols[i][3];
  try {
    const r = await this.helpers.httpRequest({ method:'GET', url:'https://query1.finance.yahoo.com/v8/finance/chart/'+encodeURIComponent(sym), qs:{ range:'5d', interval:'1d' }, json:true, headers:{ 'User-Agent':'Mozilla/5.0' }, timeout:15000 });
    const m = r && r.chart && r.chart.result && r.chart.result[0] && r.chart.result[0].meta;
    if(!m || m.regularMarketPrice==null) continue;
    const px = Number(m.regularMarketPrice);
    const prev = Number(m.chartPreviousClose!=null ? m.chartPreviousClose : m.previousClose);
    let chg='Not specified';
    if(prev){ const pct=(px-prev)/prev*100; chg=(pct>=0?'+':'')+pct.toFixed(1)+'%'; }
    const val=pre+px.toFixed(2)+suf;
    prices.push({ name:name, value:val, change:chg, note:'' });
    dlines.push(name+': '+val+' ('+chg+' d/d)');
  } catch(e){ /* skip unavailable symbol */ }
}
const digest = dlines.length ? dlines.join('\n') : 'No live market prices were retrieved this run.';
return [{ json: Object.assign({}, inp, { marketPrices: prices, pricesDigest: digest }) }];
